class DSU(val n: Int) {
    private val parent: IntArray
    private val rank: IntArray

    init {
        parent = IntArray(n) { it }
        rank = IntArray(n) { 0 }
    }

    fun find(x: Int): Int {
        if (parent[x] != x) {
            parent[x] = find(parent[x])
        }
        return parent[x]
    }

    fun union(x: Int, y: Int): Boolean {
        val xRoot = find(x)
        val yRoot = find(y)
        if (xRoot == yRoot) return false
        if (rank[xRoot] < rank[yRoot]) {
            parent[xRoot] = yRoot
        } else {
            parent[yRoot] = xRoot
            if (rank[xRoot] == rank[yRoot]) {
                rank[xRoot]++
            }
        }
        return true
    }
}

